package com.weib.entity;
import jakarta.persistence.*; import lombok.Data; import java.time.LocalDateTime;
@Entity @Table(name="forum_posts", indexes={@Index(name="idx_forum_posts_section_status_created",columnList="section_id,status,created_at"),@Index(name="idx_forum_posts_status_hot",columnList="status,like_count,comment_count")}) @Data
public class ForumPost { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @Column(name="section_id",nullable=false) private Long sectionId; @Column(name="author_id",nullable=false) private Long authorId; @Column(name="author_role",nullable=false,length=20) private String authorRole; @Column(nullable=false,length=120) private String title; @Column(nullable=false,columnDefinition="TEXT") private String content; @Column(name="image_urls",columnDefinition="TEXT") private String imageUrls; @Column(length=500) private String tags; @Column(nullable=false,length=20) private String status="ACTIVE"; @Column(name="like_count",nullable=false) private Integer likeCount=0; @Column(name="comment_count",nullable=false) private Integer commentCount=0; @Column(name="favorite_count",nullable=false) private Integer favoriteCount=0; @Column(name="created_at",nullable=false,updatable=false) private LocalDateTime createdAt; @Column(name="updated_at",nullable=false) private LocalDateTime updatedAt; @PrePersist protected void onCreate(){LocalDateTime n=LocalDateTime.now();createdAt=n;updatedAt=n;} @PreUpdate protected void onUpdate(){updatedAt=LocalDateTime.now();} }
